CREATE TABLE users (id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(120),email VARCHAR(120) UNIQUE,phone VARCHAR(30),password VARCHAR(255),role ENUM('patient','doctor','admin','cashier','nurse') DEFAULT 'patient',status VARCHAR(20) DEFAULT 'active',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
CREATE TABLE patients (id BIGINT PRIMARY KEY AUTO_INCREMENT,user_id BIGINT,medical_record_number VARCHAR(50),birth_date DATE NULL,gender VARCHAR(30) NULL,insurance VARCHAR(120) NULL,address TEXT NULL,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,FOREIGN KEY (user_id) REFERENCES users(id));
CREATE TABLE ai_eye_screenings (id BIGINT PRIMARY KEY AUTO_INCREMENT,patient_id BIGINT,complaint_text TEXT,symptoms JSON,duration VARCHAR(50),pain_level INT,photo_path VARCHAR(255) NULL,risk_level VARCHAR(30),analysis_summary TEXT,recommendation TEXT,rule_version VARCHAR(20),created_at TIMESTAMP NULL,FOREIGN KEY (patient_id) REFERENCES patients(id));
CREATE TABLE appointments (id BIGINT PRIMARY KEY AUTO_INCREMENT,patient_id BIGINT,service_name VARCHAR(120),appointment_date DATE,appointment_time TIME,complaint TEXT,queue_number VARCHAR(20),status VARCHAR(30),doctor_name VARCHAR(120),created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,FOREIGN KEY (patient_id) REFERENCES patients(id));
CREATE TABLE medical_reports (id BIGINT PRIMARY KEY AUTO_INCREMENT,patient_id BIGINT,appointment_id BIGINT NULL,doctor_name VARCHAR(120),visit_date DATE,right_vision VARCHAR(20),left_vision VARCHAR(20),intraocular_pressure INT,dry_eye_risk VARCHAR(30),diagnosis_summary TEXT,recommendation TEXT,status VARCHAR(20),created_at TIMESTAMP NULL);
CREATE TABLE products (id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(120),category VARCHAR(80),description TEXT,price DECIMAL(12,2),image VARCHAR(255),badge VARCHAR(80),stock INT,requires_doctor_recommendation TINYINT(1),status VARCHAR(20),created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
CREATE TABLE orders (id BIGINT PRIMARY KEY AUTO_INCREMENT,patient_id BIGINT,total_price DECIMAL(12,2),discount DECIMAL(12,2),final_price DECIMAL(12,2),status VARCHAR(30),pickup_method VARCHAR(120),created_at TIMESTAMP NULL);
CREATE TABLE order_items (id BIGINT PRIMARY KEY AUTO_INCREMENT,order_id BIGINT,product_id BIGINT NULL,service_name VARCHAR(120) NULL,item_type VARCHAR(30),name VARCHAR(120),price DECIMAL(12,2),quantity INT,subtotal DECIMAL(12,2));
CREATE TABLE family_members (id BIGINT PRIMARY KEY AUTO_INCREMENT,patient_id BIGINT,name VARCHAR(120),relationship VARCHAR(50),birth_date DATE NULL,phone VARCHAR(30) NULL,is_emergency_contact TINYINT(1) DEFAULT 0,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
CREATE TABLE rewards (id BIGINT PRIMARY KEY AUTO_INCREMENT,patient_id BIGINT,points INT DEFAULT 0,streak_days INT DEFAULT 0,checked_in_date DATE NULL,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL);
CREATE TABLE vouchers (id BIGINT PRIMARY KEY AUTO_INCREMENT,name VARCHAR(120),description TEXT,required_points INT,discount_type VARCHAR(30),discount_value DECIMAL(12,2),minimum_transaction DECIMAL(12,2),status VARCHAR(20),created_at TIMESTAMP NULL);
CREATE TABLE patient_vouchers (id BIGINT PRIMARY KEY AUTO_INCREMENT,patient_id BIGINT,voucher_id BIGINT,is_used TINYINT(1) DEFAULT 0,redeemed_at TIMESTAMP NULL,used_at TIMESTAMP NULL);
CREATE TABLE audit_logs (id BIGINT PRIMARY KEY AUTO_INCREMENT,user_id BIGINT,action VARCHAR(80),entity VARCHAR(80),entity_id BIGINT,ip_address VARCHAR(45),user_agent TEXT,created_at TIMESTAMP NULL);
